"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[8393],{55706(n,t,r){r.r(t),r.d(t,{assets:()=>d,contentTitle:()=>i,default:()=>l,frontMatter:()=>c,metadata:()=>s,toc:()=>a});const s=JSON.parse('{"id":"cpp20/contains","title":"\u5173\u8054\u5bb9\u5668 contains()","description":"C++20 \u5173\u8054\u5bb9\u5668 contains() \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/47-contains.md","sourceDirName":"cpp20","slug":"/cpp20/47-contains","permalink":"/LearnModernCpp/docs/cpp20/47-contains","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"contains","permalink":"/LearnModernCpp/docs/tags/contains"}],"version":"current","sidebarPosition":48,"frontMatter":{"sidebar_position":48,"slug":"47-contains","title":"\u5173\u8054\u5bb9\u5668 contains()","description":"C++20 \u5173\u8054\u5bb9\u5668 contains() \u6559\u5b66\u793a\u4f8b","tags":["cpp20","contains"]},"sidebar":"docs","previous":{"title":"\u5b57\u7b26\u4e32\u64cd\u4f5c (starts_with / ends_with)","permalink":"/LearnModernCpp/docs/cpp20/46-string-operations"},"next":{"title":"jthread \u548c stop_token (\u534f\u4f5c\u5f0f\u7ebf\u7a0b\u53d6\u6d88)","permalink":"/LearnModernCpp/docs/cpp20/70-jthread"}}');var e=r(74848),o=r(28453);const c={sidebar_position:48,slug:"47-contains",title:"\u5173\u8054\u5bb9\u5668 contains()",description:"C++20 \u5173\u8054\u5bb9\u5668 contains() \u6559\u5b66\u793a\u4f8b",tags:["cpp20","contains"]},i="\u5173\u8054\u5bb9\u5668 contains()",d={},a=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const t={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...n.components};return(0,e.jsxs)(e.Fragment,{children:[(0,e.jsx)(t.header,{children:(0,e.jsx)(t.h1,{id:"\u5173\u8054\u5bb9\u5668-contains",children:"\u5173\u8054\u5bb9\u5668 contains()"})}),"\n",(0,e.jsx)(t.p,{children:"C++20 \u6807\u51c6\u5f15\u5165\u7684 \u5173\u8054\u5bb9\u5668 contains() \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,e.jsx)(t.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,e.jsx)(t.pre,{children:(0,e.jsx)(t.code,{className:"language-cpp",metastring:'title="cpp20/47_contains.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u5173\u8054\u5bb9\u5668 contains()\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: C++20 \u4e3a\u6240\u6709\u5173\u8054\u5bb9\u5668\uff08map\u3001set\u3001unordered_map\u3001unordered_set\uff09\r\n *          \u6dfb\u52a0\u4e86 contains() \u6210\u5458\u51fd\u6570\uff0c\u76f4\u63a5\u8fd4\u56de bool\uff0c\r\n *          \u8868\u793a\u5bb9\u5668\u4e2d\u662f\u5426\u5b58\u5728\u6307\u5b9a\u7684\u952e\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: \u4e4b\u524d\u5224\u65ad\u5143\u7d20\u662f\u5426\u5b58\u5728\u9700\u8981 find() != end()\uff0c\r\n *             \u8bed\u6cd5\u5197\u957f\u4e14\u5bb9\u6613\u5199\u9519\u3002\r\n *             contains() \u8bed\u4e49\u66f4\u76f4\u89c2\u3001\u4ee3\u7801\u66f4\u7b80\u6d01\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u8fd4\u56de bool\uff0c\u6bd4 find() != end() \u66f4\u7b80\u6d01\r\n *   - \u9002\u7528\u4e8e\u6240\u6709\u5173\u8054\u5bb9\u5668\u548c\u65e0\u5e8f\u5173\u8054\u5bb9\u5668\r\n *   - \u4e0d\u8fd4\u56de\u8fed\u4ee3\u5668\uff08\u5982\u679c\u9700\u8981\u8fed\u4ee3\u5668\uff0c\u4ecd\u7528 find\uff09\r\n *   - \u4e0e count() != 0 \u7b49\u4ef7\uff0c\u4f46\u8bed\u4e49\u66f4\u6e05\u6670\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <map>\r\n#include <set>\r\n#include <string>\r\n#include <unordered_map>\r\n#include <unordered_set>\r\n#include <vector>\r\n\r\n// ===================== basic_usage() =====================\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // 1. std::set\r\n    std::set<int> numbers = {1, 3, 5, 7, 9};\r\n\r\n    std::cout << "-- std::set --\\n";\r\n    std::cout << "set \u5185\u5bb9: {1, 3, 5, 7, 9}\\n";\r\n    std::cout << "contains(5): " << std::boolalpha << numbers.contains(5) << "\\n";\r\n    std::cout << "contains(4): " << numbers.contains(4) << "\\n";\r\n\r\n    // 2. std::map\r\n    std::map<std::string, int> ages = {\r\n        {"\u5f20\u4e09", 25},\r\n        {"\u674e\u56db", 30},\r\n        {"\u738b\u4e94", 28}\r\n    };\r\n\r\n    std::cout << "\\n-- std::map --\\n";\r\n    std::cout << "contains(\\"\u5f20\u4e09\\"): " << ages.contains("\u5f20\u4e09") << "\\n";\r\n    std::cout << "contains(\\"\u8d75\u516d\\"): " << ages.contains("\u8d75\u516d") << "\\n";\r\n\r\n    // 3. std::unordered_set\r\n    std::unordered_set<std::string> fruits = {"\u82f9\u679c", "\u9999\u8549", "\u6a59\u5b50"};\r\n\r\n    std::cout << "\\n-- std::unordered_set --\\n";\r\n    std::cout << "contains(\\"\u82f9\u679c\\"): " << fruits.contains("\u82f9\u679c") << "\\n";\r\n    std::cout << "contains(\\"\u897f\u74dc\\"): " << fruits.contains("\u897f\u74dc") << "\\n";\r\n\r\n    // 4. std::unordered_map\r\n    std::unordered_map<int, std::string> codes = {\r\n        {200, "OK"},\r\n        {404, "Not Found"},\r\n        {500, "Internal Server Error"}\r\n    };\r\n\r\n    std::cout << "\\n-- std::unordered_map --\\n";\r\n    std::cout << "contains(200): " << codes.contains(200) << "\\n";\r\n    std::cout << "contains(301): " << codes.contains(301) << "\\n";\r\n\r\n    // 5. std::multiset / std::multimap\r\n    std::multiset<int> multi_nums = {1, 1, 2, 3, 3, 3};\r\n    std::cout << "\\n-- std::multiset --\\n";\r\n    std::cout << "contains(1): " << multi_nums.contains(1) << "\\n";\r\n    std::cout << "contains(4): " << multi_nums.contains(4) << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // ---- \u4e0e\u4f20\u7edf\u65b9\u5f0f\u5bf9\u6bd4 ----\r\n    std::cout << "-- \u4e0e\u4f20\u7edf\u65b9\u5f0f\u5bf9\u6bd4 --\\n\\n";\r\n\r\n    std::map<std::string, int> scores = {\r\n        {"\u6570\u5b66", 95},\r\n        {"\u8bed\u6587", 88},\r\n        {"\u82f1\u8bed", 92}\r\n    };\r\n\r\n    std::string subject = "\u6570\u5b66";\r\n\r\n    // C++20: contains()\r\n    if (scores.contains(subject)) {\r\n        std::cout << "[C++20 contains] " << subject << " \u5b58\u5728, \u5206\u6570: " << scores[subject] << "\\n";\r\n    }\r\n\r\n    // C++17: find() != end()\r\n    if (auto it = scores.find(subject); it != scores.end()) {\r\n        std::cout << "[C++17 find] " << subject << " \u5b58\u5728, \u5206\u6570: " << it->second << "\\n";\r\n    }\r\n\r\n    // \u66f4\u65e9: count() != 0\r\n    if (scores.count(subject) != 0) {\r\n        std::cout << "[count] " << subject << " \u5b58\u5728\\n";\r\n    }\r\n\r\n    // ---- \u5b9e\u9645\u5e94\u7528\u573a\u666f ----\r\n    std::cout << "\\n-- \u5b9e\u9645\u5e94\u7528\uff1a\u6743\u9650\u68c0\u67e5 --\\n";\r\n    std::set<std::string> permissions = {"read", "write", "execute"};\r\n\r\n    auto check_permission = [&permissions](const std::string& perm) {\r\n        if (permissions.contains(perm)) {\r\n            std::cout << "  [\u5141\u8bb8] " << perm << "\\n";\r\n        } else {\r\n            std::cout << "  [\u62d2\u7edd] " << perm << "\\n";\r\n        }\r\n    };\r\n\r\n    check_permission("read");\r\n    check_permission("write");\r\n    check_permission("admin");\r\n    check_permission("delete");\r\n\r\n    // ---- \u9ed1\u540d\u5355/\u767d\u540d\u5355 ----\r\n    std::cout << "\\n-- \u9ed1\u540d\u5355\u8fc7\u6ee4 --\\n";\r\n    std::unordered_set<std::string> blacklist = {"spam", "virus", "malware"};\r\n    std::vector<std::string> messages = {"hello", "spam", "\u4f60\u597d", "virus", "C++20"};\r\n\r\n    for (const auto& msg : messages) {\r\n        if (blacklist.contains(msg)) {\r\n            std::cout << "  [\u62e6\u622a] " << msg << "\\n";\r\n        } else {\r\n            std::cout << "  [\u901a\u8fc7] " << msg << "\\n";\r\n        }\r\n    }\r\n\r\n    // ---- \u914d\u7f6e\u67e5\u627e ----\r\n    std::cout << "\\n-- \u914d\u7f6e\u67e5\u627e --\\n";\r\n    std::map<std::string, std::string> config = {\r\n        {"host", "localhost"},\r\n        {"port", "8080"},\r\n        {"debug", "true"}\r\n    };\r\n\r\n    auto get_config = [&config](const std::string& key,\r\n                                 const std::string& default_val = "") -> std::string {\r\n        if (config.contains(key)) {\r\n            return config[key];\r\n        }\r\n        return default_val;\r\n    };\r\n\r\n    std::cout << "  host: " << get_config("host") << "\\n";\r\n    std::cout << "  port: " << get_config("port") << "\\n";\r\n    std::cout << "  debug: " << get_config("debug") << "\\n";\r\n    std::cout << "  timeout: " << get_config("timeout", "30") << " (\u9ed8\u8ba4\u503c)\\n";\r\n\r\n    // ---- \u4e0e ranges \u914d\u5408 ----\r\n    std::cout << "\\n-- \u4e0e\u5176\u4ed6 C++20 \u7279\u6027\u914d\u5408 --\\n";\r\n    std::set<int> valid_ids = {1, 3, 5, 7, 9};\r\n    std::vector<int> request_ids = {1, 2, 3, 4, 5, 6, 7};\r\n\r\n    std::cout << "\u6709\u6548\u8bf7\u6c42: ";\r\n    for (int id : request_ids) {\r\n        if (valid_ids.contains(id)) {\r\n            std::cout << id << " ";\r\n        }\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1acontains \u53ea\u5224\u65ad\u5b58\u5728\u6027\uff0c\u4e0d\u8fd4\u56de\u8fed\u4ee3\u5668\r\n    std::cout << "1. contains() \u53ea\u8fd4\u56de bool:\\n";\r\n    std::cout << "   \u5982\u679c\u9700\u8981\u83b7\u53d6\u503c\uff0c\u4ecd\u9700\u4f7f\u7528 find():\\n";\r\n    std::map<std::string, int> m = {{"key", 42}};\r\n    if (m.contains("key")) {\r\n        // \u5df2\u77e5\u5b58\u5728\uff0c\u4f46\u8fd8\u9700\u8981\u518d\u627e\u4e00\u6b21\u624d\u80fd\u83b7\u53d6\u503c\r\n        // \u6548\u7387\u4e0a\u6709\u53cc\u91cd\u67e5\u627e\u7684\u5f00\u9500\r\n        std::cout << "   contains + []: " << m["key"] << "\\n";\r\n    }\r\n    // \u66f4\u597d\u7684\u65b9\u5f0f\uff08\u5982\u679c\u9700\u8981\u503c\uff09\uff1a\r\n    if (auto it = m.find("key"); it != m.end()) {\r\n        std::cout << "   find + ->second: " << it->second << " (\u53ea\u67e5\u627e\u4e00\u6b21)\\n";\r\n    }\r\n    std::cout << "\\n";\r\n\r\n    // \u9677\u96312\uff1avector/array \u6ca1\u6709 contains\r\n    std::cout << "2. vector/array \u6ca1\u6709 contains() \u6210\u5458\u51fd\u6570:\\n";\r\n    std::cout << "   \u53ea\u6709\u5173\u8054\u5bb9\u5668\u6709 contains()\\n";\r\n    std::cout << "   \u5bf9\u4e8e vector\uff0c\u4f7f\u7528 std::find \u6216 std::ranges::find\\n";\r\n    std::vector<int> v = {1, 2, 3, 4, 5};\r\n    bool found = std::find(v.begin(), v.end(), 3) != v.end();\r\n    std::cout << "   vector \u67e5\u627e 3: " << std::boolalpha << found << "\\n\\n";\r\n\r\n    // \u9677\u96313\uff1amultimap/multiset \u7684 contains \u53ea\u5224\u65ad\u662f\u5426\u5b58\u5728\r\n    std::cout << "3. multimap/multiset \u7684 contains \u4e0d\u544a\u8bc9\u4f60\u6709\u51e0\u4e2a:\\n";\r\n    std::multiset<int> ms = {1, 1, 2, 2, 2, 3};\r\n    std::cout << "   multiset{1,1,2,2,2,3}.contains(2) = " << ms.contains(2) << "\\n";\r\n    std::cout << "   multiset{1,1,2,2,2,3}.count(2) = " << ms.count(2) << "\\n";\r\n    std::cout << "   \u5982\u679c\u9700\u8981\u8ba1\u6570\uff0c\u4ecd\u4f7f\u7528 count()\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u4e0e count \u7684\u6027\u80fd\u5bf9\u6bd4\r\n    std::cout << "4. contains() vs count() \u7684\u6027\u80fd:\\n";\r\n    std::cout << "   \u5bf9\u4e8e set/map: \u4e24\u8005\u6027\u80fd\u76f8\u540c\uff08O(log n)\uff09\\n";\r\n    std::cout << "   \u5bf9\u4e8e multiset/multimap: contains \u53ef\u80fd\u66f4\u5feb\\n";\r\n    std::cout << "   \u56e0\u4e3a contains \u627e\u5230\u4e00\u4e2a\u5c31\u8fd4\u56de\uff0ccount \u8981\u6570\u5b8c\u6240\u6709\\n\\n";\r\n\r\n    // \u9677\u96315\uff1a\u900f\u660e\u6bd4\u8f83\u5668\r\n    std::cout << "5. \u4f7f\u7528\u900f\u660e\u6bd4\u8f83\u5668\u53ef\u4ee5\u907f\u514d\u4e34\u65f6\u5bf9\u8c61:\\n";\r\n    std::set<std::string, std::less<>> transparent_set = {"hello", "world"};\r\n    // \u4f7f\u7528 std::less<> \u540e\uff0c\u53ef\u4ee5\u76f4\u63a5\u7528 const char* \u67e5\u627e\r\n    bool has_hello = transparent_set.contains("hello");  // \u4e0d\u521b\u5efa\u4e34\u65f6 string\r\n    std::cout << "   \u900f\u660e\u6bd4\u8f83\u5668\u67e5\u627e: " << has_hello << "\\n";\r\n    std::cout << "   \u907f\u514d\u4e86\u4ece const char* \u6784\u9020\u4e34\u65f6 std::string\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u5173\u8054\u5bb9\u5668 contains() - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,e.jsx)(t.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,e.jsxs)(t.ul,{children:["\n",(0,e.jsx)(t.li,{children:(0,e.jsx)(t.a,{href:"https://en.cppreference.com/w/cpp/container/map/contains",children:"cppreference: \u5173\u8054\u5bb9\u5668 contains()"})}),"\n"]})]})}function l(n={}){const{wrapper:t}={...(0,o.R)(),...n.components};return t?(0,e.jsx)(t,{...n,children:(0,e.jsx)(u,{...n})}):u(n)}},28453(n,t,r){r.d(t,{R:()=>c,x:()=>i});var s=r(96540);const e={},o=s.createContext(e);function c(n){const t=s.useContext(o);return s.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function i(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(e):n.components||e:c(n.components),s.createElement(o.Provider,{value:t},n.children)}}}]);